-- ============================================================
-- TOUR ATOMS — атомарная база компонентов туров
-- ============================================================

CREATE TABLE IF NOT EXISTS public.tour_atoms (
  id              TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  icon            TEXT DEFAULT '',
  category        TEXT NOT NULL,
  "group"         TEXT NOT NULL,
  duration_hours  INT,
  net             INT NOT NULL DEFAULT 0,
  sell            INT NOT NULL DEFAULT 0,
  mgr             INT NOT NULL DEFAULT 0,
  pricing_unit    TEXT NOT NULL DEFAULT 'per_pax',
  divisible       BOOLEAN NOT NULL DEFAULT false,
  tags            TEXT[] DEFAULT '{}',
  notes           TEXT DEFAULT '',
  active          BOOLEAN NOT NULL DEFAULT true,
  sort_order      INT NOT NULL DEFAULT 0,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_atoms_cat   ON public.tour_atoms(category);
CREATE INDEX IF NOT EXISTS idx_atoms_group ON public.tour_atoms("group");
CREATE INDEX IF NOT EXISTS idx_atoms_active ON public.tour_atoms(active);

ALTER TABLE public.tour_atoms ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "atoms_select" ON public.tour_atoms;
DROP POLICY IF EXISTS "atoms_insert" ON public.tour_atoms;
DROP POLICY IF EXISTS "atoms_update" ON public.tour_atoms;
DROP POLICY IF EXISTS "atoms_delete" ON public.tour_atoms;
CREATE POLICY "atoms_select" ON public.tour_atoms FOR SELECT TO authenticated USING (true);
CREATE POLICY "atoms_insert" ON public.tour_atoms FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "atoms_update" ON public.tour_atoms FOR UPDATE TO authenticated USING (true);
CREATE POLICY "atoms_delete" ON public.tour_atoms FOR DELETE TO authenticated USING (true);

-- SEED: 98 атомов с placeholder ценами
DELETE FROM public.tour_atoms WHERE id LIKE 'a%';  -- чистка старых seed-записей


-- ATOMIC TOURS — таблица для собранных атомных туров
CREATE TABLE IF NOT EXISTS public.atomic_tours (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by      UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  client_name     TEXT NOT NULL DEFAULT '',
  status          TEXT NOT NULL DEFAULT 'draft',
  pax             JSONB NOT NULL DEFAULT '{"adults":2,"children":0,"infants":0}',
  mode            TEXT NOT NULL DEFAULT 'group',
  selected        JSONB NOT NULL DEFAULT '[]',
  total_sell      INT NOT NULL DEFAULT 0,
  total_net       INT NOT NULL DEFAULT 0,
  total_margin    INT NOT NULL DEFAULT 0,
  notes           TEXT NOT NULL DEFAULT '',
  metadata        JSONB NOT NULL DEFAULT '{}',
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_atom_tours_creator ON public.atomic_tours(created_by);
ALTER TABLE public.atomic_tours ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "at_select" ON public.atomic_tours;
DROP POLICY IF EXISTS "at_insert" ON public.atomic_tours;
DROP POLICY IF EXISTS "at_update" ON public.atomic_tours;
DROP POLICY IF EXISTS "at_delete" ON public.atomic_tours;
CREATE POLICY "at_select" ON public.atomic_tours FOR SELECT TO authenticated
  USING (created_by = auth.uid() OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));
CREATE POLICY "at_insert" ON public.atomic_tours FOR INSERT TO authenticated WITH CHECK (created_by = auth.uid());
CREATE POLICY "at_update" ON public.atomic_tours FOR UPDATE TO authenticated
  USING (created_by = auth.uid() OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));
CREATE POLICY "at_delete" ON public.atomic_tours FOR DELETE TO authenticated
  USING (created_by = auth.uid() OR EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = auth.uid() AND role = 'booking'));


SELECT 'Atoms: ' || COUNT(*) || ' rows' FROM public.tour_atoms;